import UIKit
import GoogleMaps
import Stripe

class ViewController: UIViewController {

    override func viewDidLoad() {
        super.viewDidLoad()
        setupGoogleMaps()
        setupStripe()
    }

    func setupGoogleMaps() {
        let camera = GMSCameraPosition.camera(withLatitude: 37.7749, longitude: -122.4194, zoom: 10.0)
        let mapView = GMSMapView.map(withFrame: self.view.bounds, camera: camera)
        self.view.addSubview(mapView)
        
        let marker = GMSMarker()
        marker.position = CLLocationCoordinate2D(latitude: 37.7749, longitude: -122.4194)
        marker.title = "San Francisco"
        marker.map = mapView
    }
    
    func setupStripe() {
        STPPaymentConfiguration.shared().publishableKey = "pk_test_Stripe51234567890"
    }

    @IBAction func payButtonTapped(_ sender: UIButton) {
        let paymentIntentClientSecret = "your_payment_intent_client_secret_here"
        let cardParams = STPPaymentMethodCardParams()
        cardParams.number = "4242424242424242"
        cardParams.expMonth = 12
        cardParams.expYear = 25
        cardParams.cvc = "123"

        let paymentMethod = STPPaymentMethodParams(card: cardParams, billingDetails: nil, metadata: nil)

        STPAPIClient.shared().createPaymentMethod(with: paymentMethod) { (paymentMethod, error) in
            if let error = error {
                print("Error creating payment method: \(error)")
                return
            }
            self.confirmPayment(paymentMethod: paymentMethod!.stripeId, clientSecret: paymentIntentClientSecret)
        }
