    func confirmPayment(paymentMethod: String, clientSecret: String) {
        let paymentIntentParams = STPPaymentIntentParams(clientSecret: clientSecret)
        paymentIntentParams.paymentMethodId = paymentMethod

        STPAPIClient.shared().confirmPaymentIntent(paymentIntentParams) { (paymentIntent, error) in
